use clap::{Parser, Subcommand, ValueEnum};
use laverna::prelude::*;
use laverna::strategy::{synthesize_strategy, StrategyReport};

// Compiled-in seed corpus (generated by build.rs). Embedded unconditionally so
// the binary is self-contained from any CWD — fixes T35.
include!(concat!(env!("OUT_DIR"), "/embedded.rs"));
use serde_json::Value;
use std::borrow::Cow;
use std::io::{BufRead, Write};

/// Output format selector for machine-readable (`json`) vs human (`text`) output.
#[derive(Clone, Copy, Debug, PartialEq, Eq, ValueEnum)]
enum OutputFormat {
    Text,
    Json,
}

#[derive(Parser)]
#[command(
    name = "laverna",
    about = "Laverna — deterministic Vedic reasoning engine",
    long_about = "Laverna maps a question onto the 9-graha wheel and reasons \
back down to proof (NAND-to-bankai). It never guesses: out-of-scope input fails \
loudly instead of hallucinating.",
    version,
    after_long_help = "EXAMPLES:\n  laverna ping\n  laverna solve --query \"2 + 3 = 5\"\n  laverna solve --query \"10 % 3 = 1\" --format json\n  laverna solve --batch < queries.jsonl\n  laverna route --query \"how should we architect for LLM safety?\" --format json\n  laverna chart -d \"1994-04-14 20:09\" --latitude 45.4 --longitude -92.9 --format json\n  laverna validate \"2 + 3 = 5\" --format json\n  laverna formulas --domain health"
)]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Health check (prints "pong")
    Ping,
    /// Show version and enabled features
    Info,
    /// Full reasoning pipeline: descent → formula → Tanto evaluation
    Solve {
        /// Natural-language or structured query (omit with --batch to read stdin)
        #[arg(short, long)]
        query: Option<String>,
        /// Verbose output with provenance chains
        #[arg(short, long)]
        verbose: bool,
        /// Richer trace: per-token graha decomposition + provenance chains
        #[arg(long)]
        explain: bool,
        /// Output format: text (default) or json
        #[arg(long, value_enum, default_value_t = OutputFormat::Text)]
        format: OutputFormat,
        /// Read queries from stdin (JSONL `{"query": "..."}` or one per line); emits JSONL
        #[arg(long)]
        batch: bool,
    },
    /// Reverse-route a query to a strategy via the 9-graha wheel
    Route {
        /// Natural-language query to turn into a strategy
        #[arg(short, long)]
        query: Option<String>,
        /// Comma-separated repo list to turn into an assimilation playbook
        #[arg(short = 'R', long = "repos")]
        repos: Option<String>,
        /// Show the per-token graha decomposition
        #[arg(short, long)]
        verbose: bool,
        /// Richer trace: always show the per-token graha decomposition
        #[arg(long)]
        explain: bool,
        /// Output format: text (default) or json
        #[arg(long, value_enum, default_value_t = OutputFormat::Text)]
        format: OutputFormat,
    },
    /// Look up an archetypal seed entity by ID
    EntityGet {
        /// Entity ID (e.g., "shukra", "bipolar_disorder")
        entity_id: String,
    },
    /// Cast a Vedic birth chart (lagna + 12 bhavas) for a datetime + location
    Chart {
        /// ISO datetime: YYYY-MM-DD HH:MM:SS
        #[arg(short, long)]
        datetime: String,
        /// Location name (optional, resolves lagna + bhavas)
        #[arg(short, long)]
        location: Option<String>,
        /// Observer latitude in degrees (N positive) for lagna + bhavas
        #[arg(long, allow_hyphen_values = true)]
        latitude: Option<f64>,
        /// Observer longitude in degrees (E positive) for lagna + bhavas
        #[arg(long, allow_hyphen_values = true)]
        longitude: Option<f64>,
        /// Richer trace: print the graha aspect matrix
        #[arg(long)]
        explain: bool,
        /// Output format: text (default) or json
        #[arg(long, value_enum, default_value_t = OutputFormat::Text)]
        format: OutputFormat,
    },
    /// Verify a Tanto formula expression
    Validate {
        /// Expression to validate (e.g., "2 + 3 = 5")
        expression: String,
        /// Output format: text (default) or json
        #[arg(long, value_enum, default_value_t = OutputFormat::Text)]
        format: OutputFormat,
    },
    /// List loaded formulas (optionally filtered by domain)
    Formulas {
        /// Filter by domain keyword
        #[arg(short, long)]
        domain: Option<String>,
        /// Max results
        #[arg(short, long, default_value = "20")]
        limit: usize,
    },
    /// List loaded seed entities (optionally filtered)
    Entities {
        /// Filter by keyword
        #[arg(short, long)]
        filter: Option<String>,
        /// Filter by graha domain (e.g. "surya", "rahu")
        #[arg(short = 'D', long = "domain")]
        domain: Option<String>,
        /// Max results
        #[arg(short, long, default_value = "20")]
        limit: usize,
    },
    /// Solve a domain-agnostic stat/point-allocation optimization from a schema
    Optimize {
        /// Path to the TOML optimization schema
        #[arg(short, long)]
        schema: String,
        /// Return N distinct Pareto-optimal allocations
        #[arg(short = 'K', long = "top-k", default_value = "1")]
        top_k: usize,
        /// Dump the per-item marginal-value trace for each solution
        #[arg(short, long)]
        explain: bool,
    },
    /// Print the canonical TOML template for a subcommand's input (self-describing)
    Schema {
        /// Schema name: optimize
        name: String,
    },
    /// Start MCP JSON-RPC server on stdin/stdout
    #[cfg(feature = "mcp")]
    Mcp,
    /// Run web search (World Bank stats)
    #[cfg(feature = "websearch")]
    Websearch {
        /// Search query
        query: String,
    },
}

fn main() {
    let cli = Cli::parse();

    match cli.command {
        Commands::Ping => println!("pong"),
        Commands::Info => {
            let formula_reg = load_formula_registry();
            let entity_reg = load_entity_registry();
            println!("laverna {}", env!("CARGO_PKG_VERSION"));
            println!("edition 2021");
            let features = collect_features();
            println!("features: {features}");
            println!("formulas: {}", formula_reg.len());
            println!("entities: {}", entity_reg.seed_count());
            let mut by_domain: std::collections::BTreeMap<String, usize> =
                std::collections::BTreeMap::new();
            for id in entity_reg.list_seeds() {
                if let Some(seed) = entity_reg.get_seed_ref(id) {
                    let key = seed
                        .dominant_graha()
                        .map(|g| g.name().to_string())
                        .unwrap_or_else(|| "ungrouped".to_string());
                    *by_domain.entry(key).or_insert(0) += 1;
                }
            }
            println!("entity domains (graha classification):");
            for (d, n) in &by_domain {
                println!("  {d}: {n}");
            }
        }
        Commands::Solve {
            query,
            verbose,
            explain,
            format,
            batch,
        } => {
            if batch {
                cmd_solve_batch(verbose, explain);
            } else if let Some(q) = query {
                let result = run_solve(&q);
                print_solve(&result, verbose, explain, format);
            } else {
                eprintln!("error: `solve` requires --query <Q> or --batch");
                std::process::exit(2);
            }
        }
        Commands::Route {
            query,
            repos,
            verbose,
            explain,
            format,
        } => match (query, repos) {
            (_, Some(repos_csv)) => cmd_route_repos(&repos_csv, verbose, explain, format),
            (Some(query), None) => {
                let result = run_route(&query);
                print_route(&result, verbose, explain, format);
            }
            (None, None) => {
                eprintln!("error: `route` requires --query <Q> or --repos <a,b,c>");
                std::process::exit(2);
            }
        },
        Commands::EntityGet { entity_id } => cmd_entity_get(&entity_id),
        Commands::Chart {
            datetime,
            location,
            latitude,
            longitude,
            explain,
            format,
        } => cmd_chart(
            &datetime,
            location.as_deref(),
            latitude,
            longitude,
            explain,
            format,
        ),
        Commands::Validate { expression, format } => cmd_validate(&expression, format),
        Commands::Formulas { domain, limit } => cmd_formulas(domain.as_deref(), limit),
        Commands::Entities {
            filter,
            domain,
            limit,
        } => cmd_entities(filter.as_deref(), domain.as_deref(), limit),
        Commands::Optimize {
            schema,
            top_k,
            explain,
        } => cmd_optimize(&schema, top_k, explain),
        Commands::Schema { name } => cmd_schema(&name),
        #[cfg(feature = "mcp")]
        Commands::Mcp => cmd_mcp(),
        #[cfg(feature = "websearch")]
        Commands::Websearch { query } => cmd_websearch(&query),
    }
}

// ─── Feature Detection ──────────────────────────────────────────────────────

fn collect_features() -> &'static str {
    let mut features = Vec::new();
    if cfg!(feature = "mcp") {
        features.push("mcp");
    }
    if cfg!(feature = "websearch") {
        features.push("websearch");
    }
    if cfg!(feature = "budget") {
        features.push("budget");
    }
    if cfg!(feature = "llm") {
        features.push("llm");
    }
    // Seed corpus is always embedded in the binary (T35) — surfaced for transparency.
    features.push("embedded-corpus");
    if cfg!(feature = "bench") {
        features.push("bench");
    }
    if features.is_empty() {
        "none (minimal)"
    } else {
        Box::leak(features.join(", ").into_boxed_str())
    }
}

// ─── Data Loading ───────────────────────────────────────────────────────────
//
// The seed corpus (formulas, synonyms, entities, nonmath, shikai forms, events)
// is compiled into the binary by `build.rs` (embedded.rs) and loaded here. This
// makes the binary self-contained: it returns the full corpus from any working
// directory, fixing T35 (entities/formulas previously only loaded when run from
// the repo root).

fn load_formula_registry() -> FormulaRegistry {
    let mut reg = FormulaRegistry::new();
    // Embedded `[[formula]]` corpus + search synonyms. NONMATH_TOML holds
    // `[[grammar]]` tables, which the formula registry ignores (harmless no-op
    // here, but keeps the embedded corpus available should grammar support land).
    let _ = reg.load_from_toml_str(FORMULAS_TOML);
    let _ = reg.load_synonyms_from_str(SYNONYMS_TOML);
    let _ = reg.load_from_toml_str(NONMATH_TOML);
    reg
}

fn load_entity_registry() -> EntityRegistry {
    let mut reg = EntityRegistry::new();
    let _ = reg.load_seeds_from_str(ENTITIES_TOML);
    reg
}

fn load_shikai_forms() -> ShikaiFormRegistry {
    let mut forms = ShikaiFormRegistry::new();
    let _ = forms.load_from_str(SHIKAI_FORM_TOML);
    forms
}

fn load_events() -> EventRegistry {
    let mut events = EventRegistry::new();
    let _ = events.load_from_str(EVENTS_TOML);
    events
}

// ─── solve Command ──────────────────────────────────────────────────────────

/// Extract the longest contiguous arithmetic expression from a query, keeping
/// its operators so it can be evaluated with operator precedence (via the Tanto
/// parser `validate` uses) instead of naive pairwise number addition (T36).
/// Returns `None` when no numeric/operator run is present.
fn extract_arithmetic_expression(query: &str) -> Option<String> {
    let bytes = query.as_bytes();
    let is_op_char = |b: u8| {
        b.is_ascii_digit()
            || b == b'.'
            || matches!(
                b,
                b'+' | b'-' | b'*' | b'/' | b'%' | b'^' | b'(' | b')' | b'='
            )
            || b.is_ascii_whitespace()
    };
    let mut best_start: Option<usize> = None;
    let mut best_end: usize = 0;
    let mut best_len: usize = 0;
    let mut start: Option<usize> = None;
    let mut end_run = |s: usize, e: usize| {
        let len = e - s;
        if len > best_len {
            best_len = len;
            best_start = Some(s);
            best_end = e;
        }
    };
    for (i, &b) in bytes.iter().enumerate() {
        if is_op_char(b) {
            if start.is_none() {
                start = Some(i);
            }
        } else if let Some(s) = start.take() {
            end_run(s, i);
        }
    }
    if let Some(s) = start.take() {
        end_run(s, bytes.len());
    }
    best_start
        .map(|s| {
            let mut expr: String = query[s..best_end].trim().to_string();
            while matches!(
                expr.bytes().last(),
                Some(b'+' | b'*' | b'/' | b'%' | b'^' | b'=')
            ) {
                expr.pop();
            }
            while matches!(expr.bytes().next(), Some(b'+' | b'*' | b'/' | b'%' | b'=')) {
                expr.remove(0);
            }
            expr
        })
        .filter(|e| !e.is_empty() && e.chars().any(|c| c.is_ascii_digit()))
}

/// A single operator-expression evaluation result for JSON/text output.
struct NumExpr {
    expr: String,
    lhs_value: Option<f64>,
    stated_rhs: Option<f64>,
    matches: Option<bool>,
}

/// Fully-computed `solve` result — rendered as text or JSON without recomputation.
struct SolveResult {
    query: String,
    intent: &'static str,
    domain: &'static str,
    numerical: Vec<f64>,
    matrix: SettlingMatrix,
    tanto_evals: Vec<(String, String, Option<f64>)>,
    num_exprs: Vec<NumExpr>,
    provenance: Vec<(String, Vec<ProvenanceStep>)>,
}

/// Run the full `solve` pipeline and collect every result field.
fn run_solve(query: &str) -> SolveResult {
    let formula_reg = load_formula_registry();
    let entity_reg = load_entity_registry();
    let forms = load_shikai_forms();
    let events = load_events();

    let descent_engine = DescentEngine::new(formula_reg.clone(), entity_reg.clone(), forms, events);

    let intent = parse_query_intent(query);
    let domain = determine_query_domain(query);
    let numerical = extract_numerical_values(query);

    let matrix = descent_engine.descend(query);

    let env = create_env();
    let mut tanto_evals = Vec::new();
    for token in &matrix.tokens {
        if let Some(ref expr) = token.formal_expression {
            let val = evaluate_expr(expr, &env);
            tanto_evals.push((token.text.clone(), expr.clone(), val));
        }
    }

    let mut num_exprs = Vec::new();
    if numerical.len() >= 2 {
        if let Some(expr) = extract_arithmetic_expression(query) {
            if let Some(eq_pos) = expr.find('=') {
                let lhs = expr[..eq_pos].trim();
                let rhs = expr[eq_pos + 1..].trim();
                match (evaluate_expr(lhs, &env), rhs.parse::<f64>().ok()) {
                    (Some(l_val), Some(r_val)) => {
                        let matches = (l_val - r_val).abs() < 1e-9;
                        num_exprs.push(NumExpr {
                            expr: expr.clone(),
                            lhs_value: Some(l_val),
                            stated_rhs: Some(r_val),
                            matches: Some(matches),
                        });
                    }
                    (Some(l_val), None) => num_exprs.push(NumExpr {
                        expr: expr.clone(),
                        lhs_value: Some(l_val),
                        stated_rhs: None,
                        matches: None,
                    }),
                    _ => num_exprs.push(NumExpr {
                        expr: expr.clone(),
                        lhs_value: None,
                        stated_rhs: None,
                        matches: None,
                    }),
                }
            } else if let Some(val) = evaluate_expr(&expr, &env) {
                num_exprs.push(NumExpr {
                    expr: expr.clone(),
                    lhs_value: Some(val),
                    stated_rhs: None,
                    matches: None,
                });
            } else {
                num_exprs.push(NumExpr {
                    expr: expr.clone(),
                    lhs_value: None,
                    stated_rhs: None,
                    matches: None,
                });
            }
        }
    }

    let provenance = matrix
        .tokens
        .iter()
        .filter(|t| !t.provenance.is_empty())
        .map(|t| (t.text.clone(), t.provenance.clone()))
        .collect();

    SolveResult {
        query: query.to_string(),
        intent,
        domain,
        numerical,
        matrix,
        tanto_evals,
        num_exprs,
        provenance,
    }
}

/// Render `solve` as text or JSON.
fn print_solve(result: &SolveResult, verbose: bool, explain: bool, format: OutputFormat) {
    if format == OutputFormat::Json {
        let value = solve_to_json(result);
        println!("{}", serde_json::to_string(&value).unwrap());
        return;
    }

    println!("intent: {}", result.intent);
    println!("domain: {}", result.domain);
    if !result.numerical.is_empty() {
        println!("numerical: {:?}", result.numerical);
    }

    println!();
    println!(
        "descent: {:.0}% resolution, {:.2}/6 avg depth, {:.0}% NAND",
        result.matrix.resolution_score * 100.0,
        result.matrix.average_depth,
        result.matrix.nand_completeness() * 100.0,
    );

    for token in &result.matrix.tokens {
        let depth = token.settled_layer.depth();
        let layer = token.settled_layer.name();
        print!("  \"{}\" → {layer} (d{depth})", token.text);
        if !token.domains.is_empty() {
            let domains: Vec<_> = token.domains.iter().map(|d| format!("{d:?}")).collect();
            print!(", domains: [{}]", domains.join(", "));
        }
        if !token.formulas.is_empty() {
            print!(", formulas: {}", token.formulas.len());
        }
        if let Some(ref entity) = token.entity {
            print!(", entity: {entity}");
        }
        if let Some(ref formal) = token.formal_expression {
            print!(", formal: \"{formal}\"");
        }
        if token.is_absolute {
            print!(", NAND: absolute");
        }
        println!();
    }

    // Tanto math evaluation for formal expressions
    if !result.tanto_evals.is_empty() {
        println!();
        println!("tanto evaluations:");
        for (token, expr, val) in &result.tanto_evals {
            match val {
                Some(v) => println!("  {token} ({expr}) = {v:.4}"),
                None => println!("  {token} ({expr}) = error: evaluation failed"),
            }
        }
    }

    // Numerical evaluation
    if !result.num_exprs.is_empty() {
        println!();
        println!("numerical expressions:");
        for e in &result.num_exprs {
            match (e.lhs_value, e.stated_rhs, e.matches) {
                (Some(l), Some(r), Some(m)) => println!(
                    "  {} = {l:.4}  (stated RHS {r}: {})",
                    e.expr,
                    if m { "✓ match" } else { "✗ mismatch" }
                ),
                (Some(l), None, _) => println!("  {} = {l:.4}", e.expr),
                _ => println!("  {}: could not evaluate", e.expr),
            }
        }
    } else if result.numerical.len() >= 2 {
        println!();
        println!(
            "  (no operator expression present; scalars: {:?})",
            result.numerical
        );
    }

    // Richer trace: per-token graha decomposition (T46#4)
    if explain {
        println!();
        println!("graha decomposition:");
        for token in &result.matrix.tokens {
            let g = laverna::strategy::dominant_graha_of(token).map(|d| d.name().to_string());
            println!(
                "  \"{}\" → {}",
                token.text,
                g.unwrap_or_else(|| "—".to_string())
            );
        }
    }

    // Provenance (verbose or explain)
    if verbose || explain {
        println!();
        println!("provenance:");
        for (token, steps) in &result.provenance {
            println!("  \"{token}\" ({} steps):", steps.len());
            for (i, step) in steps.iter().enumerate() {
                match step {
                    ProvenanceStep::DomainClassification {
                        domain,
                        keyword,
                        confidence,
                    } => {
                        println!(
                            "    {}. DomainClassification: domain={keyword}→{domain}, conf={confidence:.1}",
                            i + 1
                        );
                    }
                    ProvenanceStep::FormulaMatch {
                        formula_id,
                        domain,
                        inputs,
                        output,
                    } => {
                        println!(
                            "    {}. FormulaMatch: {formula_id} [{domain}] {:?}→{output}",
                            i + 1,
                            inputs.as_slice()
                        );
                    }
                    ProvenanceStep::EntityMatch { entity_id, domain } => {
                        println!("    {}. EntityMatch: {entity_id} [{domain}]", i + 1);
                    }
                    ProvenanceStep::Unification {
                        formula_id,
                        entity_id,
                        bound_inputs,
                        ..
                    } => {
                        println!(
                            "    {}. Unification: formula={formula_id} entity={entity_id} bound={bound_inputs:?}",
                            i + 1
                        );
                    }
                    ProvenanceStep::FormalExpression { token, expression } => {
                        println!("    {}. FormalExpression: {token}=\"{expression}\"", i + 1);
                    }
                    ProvenanceStep::NandEvaluation {
                        gate,
                        inputs,
                        output,
                    } => {
                        println!("    {}. NandEvaluation: {gate}({inputs:?})={output}", i + 1);
                    }
                }
            }
        }
    }

    // Dominant domain summary
    if !result.matrix.dominant_domains.is_empty() {
        let domains: Vec<_> = result
            .matrix
            .dominant_domains
            .iter()
            .map(|d| format!("{d:?}"))
            .collect();
        println!();
        println!("dominant: [{}]", domains.join(", "));
    }
}

/// Build the JSON rendering of a `solve` result (self-describing for LLM callers).
fn solve_to_json(result: &SolveResult) -> Value {
    let mut tokens = serde_json::to_value(&result.matrix.tokens).unwrap();
    if let Value::Array(arr) = &mut tokens {
        for (i, tok_val) in arr.iter_mut().enumerate() {
            if let Some(tok) = result.matrix.tokens.get(i) {
                let graha = laverna::strategy::dominant_graha_of(tok).map(|d| d.name().to_string());
                if let Value::Object(o) = tok_val {
                    o.insert(
                        "dominant_graha".to_string(),
                        serde_json::to_value(&graha).unwrap(),
                    );
                }
            }
        }
    }
    let tanto: Vec<Value> = result
        .tanto_evals
        .iter()
        .map(|(tok, expr, val)| serde_json::json!({"token": tok, "expression": expr, "value": val}))
        .collect();
    let num_exprs: Vec<Value> = result
        .num_exprs
        .iter()
        .map(|e| {
            serde_json::json!({
                "expression": e.expr,
                "lhs_value": e.lhs_value,
                "stated_rhs": e.stated_rhs,
                "matches": e.matches
            })
        })
        .collect();
    let provenance: Vec<Value> = result
        .provenance
        .iter()
        .map(|(tok, steps)| serde_json::json!({"token": tok, "steps": steps}))
        .collect();
    serde_json::json!({
        "query": result.query,
        "intent": result.intent,
        "domain": result.domain,
        "numerical": result.numerical,
        "descent": {
            "resolution_score": result.matrix.resolution_score,
            "average_depth": result.matrix.average_depth,
            "nand_completeness": result.matrix.nand_completeness()
        },
        "tokens": tokens,
        "tanto_evaluations": tanto,
        "numerical_expressions": num_exprs,
        "provenance": provenance,
        "dominant_domains": result.matrix.dominant_domains
    })
}

/// Batch mode: read queries from stdin (JSONL `{"query": "..."}` or one per line)
/// and emit one JSON object per line (JSONL) — amortizes the registry load.
fn cmd_solve_batch(_verbose: bool, _explain: bool) {
    let stdin = std::io::stdin();
    let stdout = std::io::stdout();
    let mut out = stdout.lock();
    for line in stdin.lock().lines() {
        let line = match line {
            Ok(l) => l,
            Err(_) => break,
        };
        let line = line.trim();
        if line.is_empty() {
            continue;
        }
        let query: String = if let Ok(v) = serde_json::from_str::<Value>(line) {
            v.get("query")
                .and_then(|q| q.as_str())
                .map(|s| s.to_string())
                .unwrap_or_else(|| line.to_string())
        } else {
            line.to_string()
        };
        let result = run_solve(&query);
        let value = solve_to_json(&result);
        let _ = writeln!(out, "{}", serde_json::to_string(&value).unwrap());
    }
}

// ─── route Command (reverse routing) ──────────────────────────────────────────

/// Build the descent matrix for a routing query using the same deterministic
/// pipeline as `cmd_solve`.
fn build_route_matrix(query: &str) -> SettlingMatrix {
    let formula_reg = load_formula_registry();
    let entity_reg = load_entity_registry();
    let forms = load_shikai_forms();
    let events = load_events();
    let descent_engine = DescentEngine::new(formula_reg, entity_reg, forms, events);
    descent_engine.descend(query)
}

/// Reverse-route result — rendered as text or JSON without recomputation.
struct RouteResult {
    query: String,
    report: StrategyReport,
    /// Per-token dominant graha force as `(symbol, name)`, or `None`.
    decomposition: Vec<(String, Option<(String, String)>)>,
}

/// Reverse-route a query to a strategy: descent → dominant graha forces →
/// synthesized action framework. Mirrors `cmd_solve`'s descent setup so the
/// strategy is grounded in the same deterministic pipeline.
fn run_route(query: &str) -> RouteResult {
    let matrix = build_route_matrix(query);
    let report: StrategyReport = synthesize_strategy(query, &matrix);
    let decomposition = matrix
        .tokens
        .iter()
        .map(|t| {
            let g = laverna::strategy::dominant_graha_of(t)
                .map(|d| (d.symbol().to_string(), d.name().to_string()));
            (t.text.clone(), g)
        })
        .collect();
    RouteResult {
        query: query.to_string(),
        report,
        decomposition,
    }
}

/// Render one graha `Domain` (or null) as a JSON object.
fn domain_value(g: Option<Domain>) -> Value {
    match g {
        Some(d) => serde_json::json!({
            "symbol": d.symbol(),
            "name": d.name(),
            "full_name": d.full_name(),
            "archetype": d.archetype(),
            "index": d.index()
        }),
        None => Value::Null,
    }
}

/// Render `route` as text or JSON.
fn print_route(result: &RouteResult, verbose: bool, explain: bool, format: OutputFormat) {
    if format == OutputFormat::Json {
        println!("{}", serde_json::to_string(&route_to_json(result)).unwrap());
        return;
    }

    println!("{}", result.report.format());

    if verbose || explain {
        println!();
        println!("decomposition (each token → dominant force):");
        for (token, g) in &result.decomposition {
            match g {
                Some((sym, name)) => println!("  \"{token}\" → {sym} ({name})"),
                None => println!("  \"{token}\" → (no graha force)"),
            }
        }
    }
}

/// Build the JSON rendering of a `route` result.
fn route_to_json(result: &RouteResult) -> Value {
    let forces: Vec<Value> = result
        .report
        .ranked
        .iter()
        .map(|(g, count, share)| {
            serde_json::json!({
                "symbol": g.symbol(),
                "name": g.name(),
                "full_name": g.full_name(),
                "archetype": g.archetype(),
                "index": g.index(),
                "hits": count,
                "share": share
            })
        })
        .collect();
    let decomposition: Vec<Value> = result
        .decomposition
        .iter()
        .map(|(token, g)| {
            serde_json::json!({"token": token, "symbol": g.as_ref().map(|(s, _)| s), "name": g.as_ref().map(|(_, n)| n)})
        })
        .collect();
    serde_json::json!({
        "query": result.query,
        "forces": forces,
        "primary": domain_value(result.report.primary),
        "secondary": domain_value(result.report.secondary),
        "tertiary": domain_value(result.report.tertiary),
        "decomposition": decomposition
    })
}

