/// Turn a comma-separated repo list into an assimilation playbook. Each repo is
/// reverse-routed through the same deterministic descent pipeline; the dominant
/// graha force decides its default ecosystem target when no specific profile exists.
fn cmd_route_repos(repos_csv: &str, verbose: bool, explain: bool, format: OutputFormat) {
    let repos: Vec<&str> = repos_csv
        .split(',')
        .map(str::trim)
        .filter(|s| !s.is_empty())
        .collect();
    if repos.is_empty() {
        eprintln!("error: --repos requires a non-empty comma-separated list");
        std::process::exit(2);
    }

    let mut entries: Vec<Value> = Vec::new();
    for repo in repos {
        let profile = repo_profile(repo);
        let matrix = build_route_matrix(&profile.descriptor);
        let report = synthesize_strategy(&profile.descriptor, &matrix);

        let primary = report.primary;
        let target = profile.target;
        let default = primary
            .map(laverna::strategy::graha_default_target)
            .unwrap_or("—");

        let decomposition: Vec<Value> = if verbose || explain {
            matrix
                .tokens
                .iter()
                .map(|t| {
                    let g = laverna::strategy::dominant_graha_of(t)
                        .map(|d| (d.symbol().to_string(), d.name().to_string()));
                    serde_json::json!({"token": t.text, "symbol": g.as_ref().map(|(s, _)| s), "name": g.as_ref().map(|(_, n)| n)})
                })
                .collect()
        } else {
            Vec::new()
        };

        if format == OutputFormat::Json {
            entries.push(serde_json::json!({
                "repo": profile.name,
                "descriptor": profile.descriptor,
                "force": domain_value(primary),
                "target": target,
                "default_if_unknown": default,
                "note": profile.note,
                "decomposition": decomposition
            }));
            continue;
        }

        println!("● {}", profile.name);
        match primary {
            Some(g) => println!(
                "    force:  {} {} — {}",
                g.symbol(),
                g.name(),
                laverna::strategy::strategy_principle(g)
            ),
            None => println!("    force:  (no graha force resolved)"),
        }
        println!("    target: {}", target);
        println!("    default-if-unknown: {}", default);
        println!("    note:   {}", profile.note);

        if verbose || explain {
            println!("    decomposition:");
            for token in &matrix.tokens {
                match laverna::strategy::dominant_graha_of(token) {
                    Some(g) => println!("      \"{}\" → {} ({})", token.text, g.symbol(), g.name()),
                    None => println!("      \"{}\" → (no graha force)", token.text),
                }
            }
        }
        println!();
    }

    if format == OutputFormat::Json {
        println!(
            "{}",
            serde_json::to_string_pretty(&serde_json::json!({"playbook": entries})).unwrap()
        );
    } else {
        println!("Playbook is deterministic — identical repo lists yield identical maps.");
    }
}

// ─── entity-get Command ─────────────────────────────────────────────────────

fn cmd_entity_get(entity_id: &str) {
    let entity_reg = load_entity_registry();

    // Try seed lookup first
    if let Some(seed) = entity_reg.get_seed_ref(entity_id) {
        println!("id: {}", seed.id);
        println!("name: {}", seed.name);
        println!("description: {}", seed.description);
        if !seed.properties.is_empty() {
            println!("properties:");
            let mut props: Vec<_> = seed.properties.iter().collect();
            props.sort_by_key(|(k, _)| (*k).clone());
            for (key, value) in props {
                println!("  {key}: {value}");
            }
        }
        if !seed.constants.is_empty() {
            println!("constants:");
            let mut consts: Vec<_> = seed.constants.iter().collect();
            consts.sort_by_key(|(k, _)| (*k).clone());
            for (key, value) in consts {
                println!("  {key}: {value}");
            }
        }
        if !seed.tags.is_empty() {
            println!("tags: {:?}", seed.tags);
        }
        if let Some(ref formula) = seed.formula {
            println!("formula: {formula}");
        }
        if let Some(ref bija) = seed.bija {
            println!("bija: {bija}");
        }
        if let Some(ref mantra) = seed.mantra {
            println!("mantra: {mantra}");
        }
        if let Some(ref day) = seed.day {
            println!("day: {day}");
        }
        if !seed.ruled_nakshatras.is_empty() {
            println!("ruled_nakshatras: {:?}", seed.ruled_nakshatras);
        }
        return;
    }

    // Try search
    let results = entity_reg.search_seeds_ref(entity_id);
    if results.is_empty() {
        eprintln!("entity not found: {entity_id}");
        eprintln!("hint: try `laverna entities` to list all entities");
        std::process::exit(1);
    }

    println!("search results for \"{entity_id}\":");
    for seed in &results {
        println!("  {} — {}", seed.id, seed.description);
    }
}

