const GRAHA_NAMES: [&str; 9] = [
    "Surya",
    "Chandra",
    "Mangala",
    "Budha",
    "Brihaspati",
    "Shukra",
    "Shani",
    "Rahu",
    "Ketu",
];

/// Pure: validate observer coordinates are within Earth's geographic bounds.
fn validate_chart_coords(latitude: f64, longitude: f64) -> Result<(), String> {
    if !(-90.0..=90.0).contains(&latitude) {
        return Err(format!("latitude {latitude} out of range [-90, 90]"));
    }
    if !(-180.0..=180.0).contains(&longitude) {
        return Err(format!("longitude {longitude} out of range [-180, 180]"));
    }
    Ok(())
}

/// Built-in offline gazetteer for locations the user actually uses, then the
/// `xalen_houses` world-cities fallback. Deterministic; no network.
const GAZETTEER: &[(&str, f64, f64)] = &[
    ("Hinckley, MN", 46.0117, -92.9391),
    ("Hinckley, Minnesota", 46.0117, -92.9391),
    ("Hinckley", 46.0117, -92.9391),
    ("Minneapolis, MN", 44.9778, -93.2650),
    ("Minneapolis", 44.9778, -93.2650),
    ("St. Paul, MN", 44.9537, -93.0900),
    ("Duluth, MN", 46.7867, -92.1005),
    ("Pine City, MN", 45.8419, -92.9691),
    ("Sandstone, MN", 46.1283, -92.8652),
    ("Askov, MN", 46.1875, -92.7660),
];

/// Pure: resolve a city name to `(latitude, longitude)` in degrees.
fn geocode_city(name: &str) -> Option<(f64, f64)> {
    let query = name.trim().to_lowercase();
    for (city, latitude, longitude) in GAZETTEER {
        if city.to_lowercase() == query {
            return Some((*latitude, *longitude));
        }
    }
    xalen_houses::geocoding::city_coordinates(name).map(|g| (g.lat_deg(), g.lon_deg()))
}

fn cmd_chart(
    datetime: &str,
    location: Option<&str>,
    latitude: Option<f64>,
    longitude: Option<f64>,
    explain: bool,
    format: OutputFormat,
) {
    let dt = match parse_datetime(datetime) {
        Ok(dt) => dt,
        Err(e) => {
            eprintln!("error: {e}");
            std::process::exit(2);
        }
    };
    let jd = julian_day(
        dt.0 as i16,
        dt.1 as u8,
        dt.2 as u8,
        dt.3 as f64 + dt.4 as f64 / 60.0,
    );

    // Resolve observer coordinates (for lagna + bhavas).
    // Precedence: explicit --latitude/--longitude > --location city name.
    let coords: Option<(f64, f64)> = if let Some((lat, lon)) = latitude.zip(longitude) {
        if let Err(e) = validate_chart_coords(lat, lon) {
            eprintln!("error: {e}");
            std::process::exit(2);
        }
        Some((lat, lon))
    } else if let Some(loc) = location {
        match geocode_city(loc) {
            Some(g) => Some(g),
            None => {
                eprintln!("warning: unknown location '{loc}'; lagna and bhavas not computed");
                eprintln!("  use --latitude and --longitude for explicit coordinates");
                None
            }
        }
    } else {
        None
    };

    let date_str = format!("{}-{:02}-{:02} {:02}:{:02}", dt.0, dt.1, dt.2, dt.3, dt.4);
    let ayanamsa = lahiri_ayanamsa(jd);

    // Build ChartSnapshot (with location if resolved)
    let mut chart = ChartSnapshot::new(jd);
    if let Some((lat, lon)) = coords {
        chart = chart.with_location(lat, lon);
    }

    let personality = derive_personality(&chart);

    if format == OutputFormat::Json {
        let value = serde_json::json!({
            "julian_day": jd,
            "date": date_str,
            "ayanamsa": ayanamsa,
            "chart": serde_json::to_value(&chart).unwrap(),
            "personality": serde_json::to_value(&personality).unwrap()
        });
        println!("{}", serde_json::to_string_pretty(&value).unwrap());
        return;
    }

    println!("julian_day: {jd:.4}");
    println!("date: {date_str}");
    println!("ayanamsa (lahiri): {ayanamsa:.4}°");
    if coords.is_none() {
        println!("(no location given — lagna and bhavas omitted; ayanamsa is time-based, not location-based)");
    }

    // Print lagna
    if let Some(lagna) = chart.lagna {
        let extra = chart
            .ascendant_deg
            .map(|d| format!("  —  {d:.4}° sidereal"))
            .unwrap_or_default();
        println!("lagna: {} ({:?}){}", lagna.name(), lagna, extra);
    }

    // Print bhavas (house cusps)
    if !chart.house_cusps.is_empty() {
        println!();
        println!("bhavas:");
        for cusp in &chart.house_cusps {
            println!(
                "  {:>5}: {:>8.2}° {:10} ({})",
                cusp.house.name(),
                cusp.tropical,
                cusp.rashi.name(),
                cusp.house.domain(),
            );
        }
    }

    // Graha positions
    println!();
    println!("grahas:");
    for (i, name) in GRAHA_NAMES.iter().enumerate() {
        let gp = laverna::ephemeris::graha_position(Graha::from_index(i).unwrap(), jd);
        let degree_in_sign = gp.sidereal % 30.0;
        println!(
            "  {name:>12}: tropical {:>7.2}°, sidereal {:>7.2}° ({:?} {degree_in_sign:.2}°, nak {:?} pad {})",
            gp.tropical, gp.sidereal, gp.rashi, gp.nakshatra, gp.pada
        );
    }

    println!();
    println!("personality:");
    println!("  archetype: {:?}", personality.archetype);
    println!("  dominant: {:?}", personality.dominant);
    println!("  pillars: {:?}", personality.pillar_weights);

    if explain {
        println!();
        println!("aspect matrix (graha × graha):");
        for (i, row) in chart.aspect_matrix.iter().enumerate() {
            let name = GRAHA_NAMES.get(i).copied().unwrap_or("?");
            let cells: Vec<String> = row
                .iter()
                .map(|a| match a {
                    Some(asp) => format!("{asp:?}"),
                    None => ".".to_string(),
                })
                .collect();
            println!("  {name:>12}: {}", cells.join(" "));
        }
    }
}

fn parse_datetime(s: &str) -> Result<(i32, u32, u32, u32, u32), String> {
    let s = s.trim();
    if s.is_empty() {
        return Err("datetime is empty; expected YYYY-MM-DD HH:MM".to_string());
    }

    // Try "YYYY-MM-DD HH:MM" or "YYYY-MM-DD HH:MM:SS"
    let parts: Vec<&str> = s.split_whitespace().collect();
    let date_parts: Vec<u32> = parts[0].split('-').filter_map(|p| p.parse().ok()).collect();
    let time_parts: Vec<u32> = parts
        .get(1)
        .map(|t| t.split(':').filter_map(|p| p.parse().ok()).collect())
        .unwrap_or_default();

    let year = date_parts.first().copied().ok_or_else(|| {
        format!(
            "cannot parse year from '{}'; expected YYYY-MM-DD HH:MM",
            parts[0]
        )
    })? as i32;
    let month = date_parts.get(1).copied().ok_or_else(|| {
        format!(
            "cannot parse month from '{}'; expected YYYY-MM-DD HH:MM",
            parts[0]
        )
    })?;
    let day = date_parts.get(2).copied().ok_or_else(|| {
        format!(
            "cannot parse day from '{}'; expected YYYY-MM-DD HH:MM",
            parts[0]
        )
    })?;
    let hour = time_parts.first().copied().ok_or_else(|| {
        format!(
            "cannot parse hour from '{}'; expected HH:MM",
            parts.get(1).unwrap_or(&"")
        )
    })?;
    let minute = time_parts.get(1).copied().unwrap_or(0);

    // Validate ranges
    if !(1..=12).contains(&month) {
        return Err(format!("month {} out of range [1..12]", month));
    }
    if !(1..=31).contains(&day) {
        return Err(format!("day {} out of range [1..31]", day));
    }
    if hour > 23 {
        return Err(format!("hour {} out of range [0..23]", hour));
    }
    if minute > 59 {
        return Err(format!("minute {} out of range [0..59]", minute));
    }

    Ok((year, month, day, hour, minute))
}

// ─── validate Command ───────────────────────────────────────────────────────

fn cmd_validate(expression: &str, format: OutputFormat) {
    let report = verify_expression(expression);
    if format == OutputFormat::Json {
        let value = serde_json::to_value(&report).unwrap();
        println!("{}", serde_json::to_string_pretty(&value).unwrap());
        return;
    }
    println!("expression: {expression}");
    println!("passed: {}", report.passed);
    println!("diagnostics: {}", report.diagnostics.len());
    for diag in &report.diagnostics {
        println!("  {}: {}", diag.severity, diag.message);
    }
}

// ─── formulas Command ───────────────────────────────────────────────────────

fn cmd_formulas(domain: Option<&str>, limit: usize) {
    let formula_reg = load_formula_registry();

    let formulas: Vec<_> = if let Some(dom) = domain {
        formula_reg.search(dom)
    } else {
        formula_reg.all()
    };

    println!(
        "formulas (showing {} of {}):",
        formulas.len().min(limit),
        formulas.len()
    );
    for f in formulas.iter().take(limit) {
        let inputs = if f.inputs.is_empty() {
            String::new()
        } else {
            format!("{} → ", f.inputs.join(", "))
        };
        println!(
            "  {} [{4:?}]: {}{} = {}",
            f.id, inputs, f.output, f.expression, f.domain
        );
    }
}

// ─── entities Command ───────────────────────────────────────────────────────

fn cmd_entities(filter: Option<&str>, domain: Option<&str>, limit: usize) {
    let entity_reg = load_entity_registry();

    let mut seeds: Vec<_> = if let Some(kw) = filter {
        entity_reg.search_seeds_ref(kw)
    } else {
        entity_reg
            .list_seeds()
            .into_iter()
            .filter_map(|id| entity_reg.get_seed_ref(id))
            .collect()
    };

    if let Some(d) = domain {
        let d = d.to_lowercase();
        seeds.retain(|seed| {
            seed.dominant_graha()
                .map(|g| g.name().to_lowercase().contains(&d))
                .unwrap_or(false)
        });
    }

    println!(
        "entities (showing {} of {}):",
        seeds.len().min(limit),
        seeds.len()
    );
    for seed in seeds.iter().take(limit) {
        let props: Vec<_> = seed.properties.keys().cloned().collect();
        println!(
            "  {} — {} [{}]",
            seed.id,
            seed.description,
            props.join(", ")
        );
    }
}

// ─── optimize Command ────────────────────────────────────────────────────────

/// Canonical, fully-commented `optimize` schema template. Printed by
/// `laverna schema optimize` so a caller (human or LLM) can learn the shape
/// without guessing from Serde errors (T44 / T46). It is itself a valid schema.
const OPTIMIZE_SCHEMA_TEMPLATE: &str = r#"# Laverna `optimize` schema — copy, edit, run:
#   laverna optimize --schema this.toml
#
# Domain-agnostic point/perk allocation solver. It maximizes
# `objective.maximize` (weighted by `objective.weights`) subject to `budget`,
# per-item `cost`, and `requires` prereq gates. Every stat produced by an item
# `effects` MUST appear in a [scoring.*] term, or validation fails loudly.

[meta]
domain = "my_game"        # freeform label
schema_version = 1        # ignored by the solver, kept for audit

[budget]
attribute_points = 22     # pool spent by attribute-type items (cost keys must match)
perk_points = 5           # pool spent by perk-type items

# Items come in two kinds:
#   type = "attribute" -> level 1..=max_level, cost scales per level
#   type = "perk"      -> boolean (level 1), gated by `requires`
[[items]]
id = "technical_ability"
type = "attribute"
cost = { attribute_points = 1 }   # cost PER LEVEL
max_level = 20
effects = { cyberware_capacity = 1.0, tech_dmg_pct = 0.5 }  # stat per level

[[items]]
id = "license_to_chrome_t1"
type = "perk"
requires = ["technical_ability>=15"]   # item_id>=level gate; a cycle is an error
cost = { perk_points = 5 }
effects = { cyberware_stat_mod_pct = 10.0 }

# Objective: maximize a weighted sum of the scores defined below.
# Every entry in `maximize` and every `weights` key MUST name a [scoring.*] table.
[objective]
maximize = ["survivability_score", "control_score"]
weights = { survivability_score = 0.5, control_score = 0.5 }

# Scoring: each score is a linear combination of stats produced by item effects.
[scoring.survivability_score]
terms = { cyberware_capacity = 1.0 }

[scoring.control_score]
terms = { cyberware_stat_mod_pct = 0.2, tech_dmg_pct = 0.1 }
"#;

fn cmd_schema(name: &str) {
    match name {
        "optimize" => print!("{OPTIMIZE_SCHEMA_TEMPLATE}"),
        other => {
            eprintln!("error: unknown schema '{other}' (known: optimize)");
            std::process::exit(2);
        }
    }
}

fn cmd_optimize(schema_path: &str, top_k: usize, explain: bool) {
    let content = match std::fs::read_to_string(schema_path) {
        Ok(c) => c,
        Err(e) => {
            eprintln!("error: cannot read schema '{schema_path}': {e}");
            std::process::exit(2);
        }
    };
    let schema = match laverna::optimize::parse_schema(&content) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("error: {e}");
            std::process::exit(2);
        }
    };
    let solutions = match laverna::optimize::solve(&schema, top_k) {
        Ok(s) => s,
        Err(e) => {
            eprintln!("error: {e}");
            std::process::exit(2);
        }
    };
    for (i, sol) in solutions.iter().enumerate() {
        println!("# solution {} (objective {:.4})", i + 1, sol.objective);
        let mut levels: Vec<(&String, &u32)> = sol.levels.iter().filter(|(_, l)| **l > 0).collect();
        levels.sort_by_key(|(id, _)| id.as_str());
        for (id, l) in levels {
            println!("  {id} = {l}");
        }
        if explain {
            print!("{}", laverna::optimize::explain(&schema, sol));
        }
    }
}

// ─── mcp Command ────────────────────────────────────────────────────────────

#[cfg(feature = "mcp")]
fn cmd_mcp() {
    use std::io::{BufRead, Write};

    eprintln!("laverna mcp: starting JSON-RPC server on stdin/stdout");

    let formula_reg = load_formula_registry();
    let entity_reg = load_entity_registry();
    let forms = load_shikai_forms();
    let events = load_events();

    let descent_engine = DescentEngine::new(formula_reg.clone(), entity_reg.clone(), forms, events);

    let stdin = std::io::stdin();
    let stdout = std::io::stdout();
    let mut reader = stdin.lock();
    let mut writer = stdout.lock();
    let mut buffer = String::new();

    loop {
        buffer.clear();
        match reader.read_line(&mut buffer) {
            Ok(0) => break, // EOF
            Ok(_) => {
                let line = buffer.trim();
                if line.is_empty() {
                    continue;
                }

                // Parse JSON-RPC request
                let response = handle_jsonrpc(line, &descent_engine, &formula_reg, &entity_reg);

                if let Some(resp) = response {
                    let resp_str = serde_json::to_string(&resp).unwrap_or_default();
                    writeln!(writer, "{resp_str}").unwrap();
                    writer.flush().unwrap();
                }
            }
            Err(e) => {
                eprintln!("read error: {e}");
                break;
            }
        }
    }
}

#[cfg(feature = "mcp")]
struct ToolOutput {
    text: String,
    structured: Option<serde_json::Value>,
}

#[cfg(feature = "mcp")]
impl ToolOutput {
    fn text_only(text: String) -> Self {
        ToolOutput {
            text,
            structured: None,
        }
    }
    fn with_structured(text: String, structured: serde_json::Value) -> Self {
        ToolOutput {
            text,
            structured: Some(structured),
        }
    }
}

#[cfg(feature = "mcp")]
fn handle_jsonrpc(
    request: &str,
    descent_engine: &DescentEngine,
    formula_reg: &FormulaRegistry,
    entity_reg: &EntityRegistry,
) -> Option<serde_json::Value> {
    let msg: serde_json::Value = match serde_json::from_str(request) {
        Ok(v) => v,
        Err(_) => {
            return Some(serde_json::json!({
                "jsonrpc": "2.0",
                "error": {"code": -32700, "message": "Parse error"},
                "id": null
            }));
        }
    };

    let method = msg["method"].as_str().unwrap_or("");
    let id = msg["id"].clone();
    let params = &msg["params"];

    match method {
        "initialize" => Some(serde_json::json!({
            "jsonrpc": "2.0",
            "result": {
                "protocolVersion": "2024-11-05",
                "capabilities": {"tools": {"listChanged": false}},
                "serverInfo": {
                    "name": "laverna",
                    "version": env!("CARGO_PKG_VERSION")
                }
            },
            "id": id
        })),
        "notifications/initialized" => None,
        "tools/list" => Some(serde_json::json!({
            "jsonrpc": "2.0",
            "result": {
                "tools": [
                    {
                        "name": "solve",
                        "title": "Laverna Solve",
                        "description": "Run the full deterministic reasoning pipeline on a query: intent + domain classification, 7-layer token descent, and Tanto exact-math evaluation. Use this as the PRIMARY tool for any computation, formula lookup, or cross-domain reasoning. Do NOT use it to fetch a raw entity record (use entity_get) or to generate a birth chart (use chart). Output is exact and reproducible; no values are invented.",
                        "inputSchema": {
                            "type": "object",
                            "properties": {
                                "query": {"type": "string", "description": "Natural-language or structured query to reason about"},
                                "verbose": {"type": "boolean", "description": "Include per-token provenance chains in the result", "default": false}
                            },
                            "required": ["query"]
                        },
                        "outputSchema": {
                            "type": "object",
                            "properties": {
                                "intent": {"type": "string"},
                                "domain": {"type": "string"},
                                "resolution": {"type": "number", "description": "Settlement confidence, 0-100"},
                                "depth": {"type": "number", "description": "Average descent depth, 0-6"},
                                "nand": {"type": "number", "description": "NAND completeness, 0-100"},
                                "tokens": {"type": "array", "items": {
                                    "type": "object",
                                    "properties": {
                                        "text": {"type": "string"},
                                        "layer": {"type": "string"},
                                        "entity": {"type": "string"},
                                        "formal": {"type": "string"},
                                        "value": {"type": "number"}
                                    }
                                }}
                            }
                        },
                        "annotations": {"readOnlyHint": true, "openWorldHint": false, "title": "Laverna Solve"}
                    },
                    {
                        "name": "entity_get",
                        "title": "Laverna Entity Lookup",
                        "description": "Look up a seed entity by exact ID, or search the embedded corpus by keyword. Returns the entity's name, description, and properties, or a ranked list of matches. Use this to inspect a known entity; use solve for reasoning over an entity. Returns only embedded, curated data — never synthesizes new facts.",
                        "inputSchema": {
                            "type": "object",
                            "properties": {
                                "entity_id": {"type": "string", "description": "Entity ID (e.g. \"surya\") or a search keyword"}
                            },
                            "required": ["entity_id"]
                        },
                        "annotations": {"readOnlyHint": true, "openWorldHint": false, "title": "Laverna Entity Lookup"}
                    },
                    {
                        "name": "chart",
                        "title": "Laverna Vedic Chart",
                        "description": "Generate a deterministic Vedic (sidereal/Lahiri) chart for a birth datetime. Pass explicit latitude/longitude, OR a location name that is geocoded to coordinates; lagna and bhavas are only computed when coordinates are available. Use this for chart generation only — use solve for reasoning about chart output. All positions are computed from VSOP87, no network calls.",
                        "inputSchema": {
                            "type": "object",
                            "properties": {
                                "datetime": {"type": "string", "description": "ISO datetime: YYYY-MM-DD HH:MM:SS"},
                                "location": {"type": "string", "description": "Location name (geocoded to coordinates; drives lagna + bhavas)"},
                                "latitude": {"type": "number", "description": "Observer latitude in degrees (N positive)"},
                                "longitude": {"type": "number", "description": "Observer longitude in degrees (E positive)"}
                            },
                            "required": ["datetime"]
                        },
                        "outputSchema": {
                            "type": "object",
                            "properties": {
                                "julian_day": {"type": "number"},
                                "ayanamsa": {"type": "number"},
                                "lagna": {"type": "string"},
                                "bhavas": {"type": "array", "items": {
                                    "type": "object",
                                    "properties": {
                                        "house": {"type": "string"},
                                        "tropical": {"type": "number"},
                                        "rashi": {"type": "string"}
                                    }
                                }},
                                "grahas": {"type": "array", "items": {
                                    "type": "object",
                                    "properties": {
                                        "name": {"type": "string"},
                                        "tropical": {"type": "number"},
                                        "sidereal": {"type": "number"},
                                        "rashi": {"type": "string"},
                                        "degree_in_sign": {"type": "number"}
                                    }
                                }}
                            }
                        },
                        "annotations": {"readOnlyHint": true, "openWorldHint": false, "title": "Laverna Vedic Chart"}
                    },
                    {
                        "name": "validate",
                        "title": "Laverna Validate",
                        "description": "Validate a mathematical or logical expression and return a structured diagnostic report (passed flag + per-issue severity/message). Use this to check a formula or expression before trusting it. Does not evaluate to a final number — use solve for that.",
                        "inputSchema": {
                            "type": "object",
                            "properties": {
                                "expression": {"type": "string", "description": "Expression to validate"}
                            },
                            "required": ["expression"]
                        },
                        "outputSchema": {
                            "type": "object",
                            "properties": {
                                "expression": {"type": "string"},
                                "passed": {"type": "boolean"},
                                "diagnostics": {"type": "array", "items": {
                                    "type": "object",
                                    "properties": {
                                        "severity": {"type": "string"},
                                        "message": {"type": "string"}
                                    }
                                }}
                            }
                        },
                        "annotations": {"readOnlyHint": true, "openWorldHint": false, "title": "Laverna Validate"}
                    },
                    {
                        "name": "formulas",
                        "title": "Laverna Formula List",
                        "description": "Search the embedded formula corpus by domain keyword, or list all formulas. Use this for discovery of available relationships; prefer solve to actually apply a formula. Pass 'limit' to cap output for token efficiency.",
                        "inputSchema": {
                            "type": "object",
                            "properties": {
                                "domain": {"type": "string", "description": "Filter by domain keyword (empty = all)"},
                                "limit": {"type": "integer", "description": "Max results returned", "default": 20}
                            }
                        },
                        "annotations": {"readOnlyHint": true, "openWorldHint": false, "title": "Laverna Formula List"}
                    },
                    {
                        "name": "entities",
                        "title": "Laverna Entity List",
                        "description": "List seed entities from the embedded corpus, optionally filtered by keyword. Use this for corpus discovery; prefer entity_get for a single known entity. Pass 'limit' to cap output for token efficiency.",
                        "inputSchema": {
                            "type": "object",
                            "properties": {
                                "filter": {"type": "string", "description": "Filter by keyword (empty = all)"},
                                "limit": {"type": "integer", "description": "Max results returned", "default": 20}
                            }
                        },
                        "annotations": {"readOnlyHint": true, "openWorldHint": false, "title": "Laverna Entity List"}
                    },
                    {
                        "name": "optimize",
                        "title": "Laverna Optimize",
                        "description": "Solve a domain-agnostic stat/point-allocation optimization from a TOML schema (see 'laverna schema optimize' for the shape). Returns top-K Pareto-optimal allocations. Use this only for allocation/optimization problems expressible in the schema; use solve for general reasoning.",
                        "inputSchema": {
                            "type": "object",
                            "properties": {
                                "schema_path": {"type": "string", "description": "Path to the TOML optimization schema"},
                                "top_k": {"type": "integer", "description": "Return N distinct Pareto-optimal allocations", "default": 1},
                                "explain": {"type": "boolean", "description": "Include the per-item marginal-value trace", "default": false}
                            },
                            "required": ["schema_path"]
                        },
                        "annotations": {"readOnlyHint": true, "openWorldHint": false, "title": "Laverna Optimize"}
                    }
                ]
            },
            "id": id
        })),
        "tools/call" => {
            let tool_name = params["name"].as_str().unwrap_or("");
            let args = &params["arguments"];

            let result = match tool_name {
                "solve" => {
                    let query = args["query"].as_str().unwrap_or("");
                    let verbose = args["verbose"].as_bool().unwrap_or(false);
                    solve_tool(query, verbose, descent_engine)
                }
                "entity_get" => {
                    let entity_id = args["entity_id"].as_str().unwrap_or("");
                    entity_get_tool(entity_id, entity_reg)
                }
                "chart" => {
                    let datetime = args["datetime"].as_str().unwrap_or("2000-01-01 12:00:00");
                    let location = args["location"].as_str();
                    let latitude = args["latitude"].as_f64();
                    let longitude = args["longitude"].as_f64();
                    chart_tool(datetime, location, latitude, longitude)
                }
                "validate" => {
                    let expression = args["expression"].as_str().unwrap_or("");
                    validate_tool(expression)
                }
                "formulas" => {
                    let domain = args["domain"].as_str();
                    let limit = args["limit"].as_u64().unwrap_or(20) as usize;
                    formulas_tool(domain, limit, formula_reg)
                }
                "entities" => {
                    let filter = args["filter"].as_str();
                    let limit = args["limit"].as_u64().unwrap_or(20) as usize;
                    entities_tool(filter, limit, entity_reg)
                }
                "optimize" => {
                    let schema_path = args["schema_path"].as_str().unwrap_or("");
                    let top_k = args["top_k"].as_u64().unwrap_or(1) as usize;
                    let explain = args["explain"].as_bool().unwrap_or(false);
                    optimize_tool(schema_path, top_k, explain)
                }
                _ => Err(format!("unknown tool: {tool_name}")),
            };

            match result {
                Ok(output) => {
                    let mut result_obj = serde_json::json!({
                        "content": [{"type": "text", "text": output.text}]
                    });
                    if let Some(structured) = output.structured {
                        result_obj["structuredContent"] = structured;
                    }
                    Some(serde_json::json!({
                        "jsonrpc": "2.0",
                        "result": result_obj,
                        "id": id
                    }))
                }
                Err(error) => Some(serde_json::json!({
                    "jsonrpc": "2.0",
                    "result": {
                        "content": [{"type": "text", "text": format!("error: {error}")}],
                        "isError": true
                    },
                    "id": id
                })),
            }
        }
        "ping" => Some(serde_json::json!({
            "jsonrpc": "2.0",
            "result": "pong",
            "id": id
        })),
        _ => Some(serde_json::json!({
            "jsonrpc": "2.0",
            "error": {"code": -32601, "message": format!("method not found: {method}")},
            "id": id
        })),
    }
}

#[cfg(feature = "mcp")]
fn solve_tool(query: &str, verbose: bool, engine: &DescentEngine) -> Result<ToolOutput, String> {
    let mut out = String::new();
    let intent = laverna::shikai::parse_query_intent(query);
    let domain = laverna::shikai::determine_query_domain(query);
    out.push_str(&format!("intent: {intent}\ndomain: {domain}\n\n"));

    let matrix = engine.descend(query);
    out.push_str(&format!(
        "resolution: {:.0}%, depth: {:.2}/6, nand: {:.0}%\n\n",
        matrix.resolution_score * 100.0,
        matrix.average_depth,
        matrix.nand_completeness() * 100.0,
    ));

    for token in &matrix.tokens {
        out.push_str(&format!(
            "\"{}\" → {} (d{})",
            token.text,
            token.settled_layer.name(),
            token.settled_layer.depth(),
        ));
        if let Some(ref entity) = token.entity {
            out.push_str(&format!(", entity: {entity}"));
        }
        if let Some(ref expr) = token.formal_expression {
            out.push_str(&format!(", formal: \"{expr}\""));
            let env = create_env();
            if let Some(val) = evaluate_expr(expr, &env) {
                out.push_str(&format!(" = {val:.4}"));
            }
        }
        out.push('\n');
    }

    if verbose {
        out.push_str("\nprovenance:\n");
        for token in &matrix.tokens {
            if !token.provenance.is_empty() {
                out.push_str(&format!(
                    "  \"{}\": {} steps\n",
                    token.text,
                    token.provenance.len()
                ));
            }
        }
    }

    let mut tokens_json = Vec::new();
    for token in &matrix.tokens {
        let mut token_json = serde_json::json!({
            "text": token.text,
            "layer": token.settled_layer.name()
        });
        if let Some(ref entity) = token.entity {
            token_json["entity"] = serde_json::json!(entity);
        }
        if let Some(ref expr) = token.formal_expression {
            token_json["formal"] = serde_json::json!(expr);
            let env = create_env();
            if let Some(value) = evaluate_expr(expr, &env) {
                token_json["value"] = serde_json::json!(value);
            }
        }
        tokens_json.push(token_json);
    }
    let structured = serde_json::json!({
        "intent": intent,
        "domain": domain,
        "resolution": matrix.resolution_score * 100.0,
        "depth": matrix.average_depth,
        "nand": matrix.nand_completeness() * 100.0,
        "tokens": tokens_json
    });
    Ok(ToolOutput::with_structured(out, structured))
}

#[cfg(feature = "mcp")]
fn entity_get_tool(entity_id: &str, reg: &EntityRegistry) -> Result<ToolOutput, String> {
    if let Some(seed) = reg.get_seed_ref(entity_id) {
        let mut out = format!(
            "id: {}\nname: {}\ndescription: {}\n",
            seed.id, seed.name, seed.description
        );
        if !seed.properties.is_empty() {
            out.push_str("properties:\n");
            let mut props: Vec<_> = seed.properties.iter().collect();
            props.sort_by_key(|(a, _)| *a);
            for (k, v) in props {
                out.push_str(&format!("  {k}: {v}\n"));
            }
        }
        Ok(ToolOutput::text_only(out))
    } else {
        let results = reg.search_seeds_ref(entity_id);
        if results.is_empty() {
            Err(format!("entity not found: {entity_id}"))
        } else {
            let mut out = format!("search results for \"{entity_id}\":\n");
            for s in &results {
                out.push_str(&format!("  {} — {}\n", s.id, s.description));
            }
            Ok(ToolOutput::text_only(out))
        }
    }
}

#[cfg(feature = "mcp")]
fn chart_tool(
    datetime: &str,
    location: Option<&str>,
    latitude: Option<f64>,
    longitude: Option<f64>,
) -> Result<ToolOutput, String> {
    let dt = parse_datetime(datetime)?;
    let jd = julian_day(
        dt.0 as i16,
        dt.1 as u8,
        dt.2 as u8,
        dt.3 as f64 + dt.4 as f64 / 60.0,
    );
    let ayanamsa = lahiri_ayanamsa(jd);

    let mut out = format!("julian_day: {jd:.4}\nayanamsa: {ayanamsa:.4}°\n\n");

    // Resolve observer coordinates for lagna + bhavas.
    let coords: Option<(f64, f64)> = if let Some((lat, lon)) = latitude.zip(longitude) {
        validate_chart_coords(lat, lon)?;
        Some((lat, lon))
    } else if let Some(loc) = location {
        geocode_city(loc)
    } else {
        None
    };

    let mut chart = ChartSnapshot::new(jd);
    if let Some((lat, lon)) = coords {
        chart = chart.with_location(lat, lon);
    }

    let lagna_name: Option<String> = chart.lagna.map(|l| l.name().to_string());
    if let Some(lagna) = chart.lagna {
        let extra = chart
            .ascendant_deg
            .map(|d| format!("  —  {d:.4}° sidereal"))
            .unwrap_or_default();
        out.push_str(&format!("lagna: {} ({:?}){}\n", lagna.name(), lagna, extra));
    }

    let mut bhavas_json = Vec::new();
    if !chart.house_cusps.is_empty() {
        out.push_str("\nbhavas:\n");
        for cusp in &chart.house_cusps {
            out.push_str(&format!(
                "  {:>5}: {:>8.2}° {:10}\n",
                cusp.house.name(),
                cusp.tropical,
                cusp.rashi.name(),
            ));
            bhavas_json.push(serde_json::json!({
                "house": cusp.house.name(),
                "tropical": cusp.tropical,
                "rashi": cusp.rashi.name()
            }));
        }
        out.push('\n');
    }

    let graha_names = [
        "Surya",
        "Chandra",
        "Mangala",
        "Budha",
        "Brihaspati",
        "Shukra",
        "Shani",
        "Rahu",
        "Ketu",
    ];

    out.push_str("grahas:\n");
    let mut grahas_json = Vec::new();
    for (i, name) in graha_names.iter().enumerate() {
        let gp = laverna::ephemeris::graha_position(Graha::from_index(i).unwrap(), jd);
        let degree_in_sign = gp.sidereal % 30.0;
        out.push_str(&format!(
            "{name:>12}: tropical {:>7.2}°, sidereal {:>7.2}° ({:?} {degree_in_sign:.2}°)\n",
            gp.tropical, gp.sidereal, gp.rashi
        ));
        grahas_json.push(serde_json::json!({
            "name": name,
            "tropical": gp.tropical,
            "sidereal": gp.sidereal,
            "rashi": gp.rashi.name(),
            "degree_in_sign": degree_in_sign
        }));
    }

    let structured = serde_json::json!({
        "julian_day": jd,
        "ayanamsa": ayanamsa,
        "lagna": lagna_name,
        "bhavas": bhavas_json,
        "grahas": grahas_json
    });
    Ok(ToolOutput::with_structured(out, structured))
}

#[cfg(feature = "mcp")]
fn validate_tool(expression: &str) -> Result<ToolOutput, String> {
    let report = verify_expression(expression);
    let mut out = format!(
        "expression: {expression}\npassed: {}\ndiagnostics: {}\n",
        report.passed,
        report.diagnostics.len()
    );
    let mut diagnostics_json = Vec::new();
    for diag in &report.diagnostics {
        out.push_str(&format!("  {}: {}\n", diag.severity, diag.message));
        diagnostics_json.push(serde_json::json!({
            "severity": format!("{:?}", diag.severity),
            "message": diag.message
        }));
    }
    let structured = serde_json::json!({
        "expression": expression,
        "passed": report.passed,
        "diagnostics": diagnostics_json
    });
    Ok(ToolOutput::with_structured(out, structured))
}

#[cfg(feature = "mcp")]
fn formulas_tool(
    domain: Option<&str>,
    limit: usize,
    reg: &FormulaRegistry,
) -> Result<ToolOutput, String> {
    let formulas = if let Some(dom) = domain {
        reg.search(dom)
    } else {
        reg.all()
    };
    let mut out = format!(
        "formulas ({} of {}):\n",
        formulas.len().min(limit),
        formulas.len()
    );
    for f in formulas.iter().take(limit) {
        let inputs = if f.inputs.is_empty() {
            String::new()
        } else {
            format!("{} → ", f.inputs.join(", "))
        };
        out.push_str(&format!(
            "  {} [{:?}]: {}{} = {}\n",
            f.id, f.domain, inputs, f.output, f.expression
        ));
    }
    Ok(ToolOutput::text_only(out))
}

#[cfg(feature = "mcp")]
fn entities_tool(
    filter: Option<&str>,
    limit: usize,
    reg: &EntityRegistry,
) -> Result<ToolOutput, String> {
    let seeds: Vec<_> = if let Some(kw) = filter {
        reg.search_seeds_ref(kw)
    } else {
        reg.list_seeds()
            .into_iter()
            .filter_map(|id| reg.get_seed_ref(id))
            .collect()
    };
    let mut out = format!(
        "entities ({} of {}):\n",
        seeds.len().min(limit),
        seeds.len()
    );
    for s in seeds.iter().take(limit) {
        let props: Vec<_> = s.properties.keys().cloned().collect();
        out.push_str(&format!(
            "  {} — {} [{}]\n",
            s.id,
            s.description,
            props.join(", ")
        ));
    }
    Ok(ToolOutput::text_only(out))
}

#[cfg(feature = "mcp")]
fn optimize_tool(schema_path: &str, top_k: usize, explain: bool) -> Result<ToolOutput, String> {
    let content = std::fs::read_to_string(schema_path)
        .map_err(|e| format!("cannot read schema '{schema_path}': {e}"))?;
    let schema = laverna::optimize::parse_schema(&content)?;
    let solutions = laverna::optimize::solve(&schema, top_k)?;
    let mut out = String::new();
    for (i, sol) in solutions.iter().enumerate() {
        out.push_str(&format!(
            "# solution {} (objective {:.4})\n",
            i + 1,
            sol.objective
        ));
        let mut levels: Vec<(&String, &u32)> = sol.levels.iter().filter(|(_, l)| **l > 0).collect();
        levels.sort_by_key(|(id, _)| id.as_str());
        for (id, l) in levels {
            out.push_str(&format!("  {id} = {l}\n"));
        }
        if explain {
            out.push_str(&laverna::optimize::explain(&schema, sol));
        }
    }
    Ok(ToolOutput::text_only(out))
}

