#[cfg(feature = "websearch")]
const WB_INDICATORS: &[(&str, &str)] = &[
    ("gdp per capita", "NY.GDP.PCAP.CD"),
    ("gdp growth", "NY.GDP.MKTP.KD.ZG"),
    ("gdp ppp", "NY.GDP.MKTP.PP.CD"),
    ("gdp", "NY.GDP.MKTP.CD"),
    ("population", "SP.POP.TOTL"),
    ("unemployment", "SL.UEM.TOTL.ZS"),
    ("life expectancy", "SP.DYN.LE00.IN"),
    ("inflation", "FP.CPI.TOTL.ZG"),
    ("co2", "EN.ATM.CO2E.KT"),
    ("fertility", "SP.DYN.TFRT.IN"),
];

#[cfg(feature = "websearch")]
const WB_COUNTRIES: &[(&str, &str)] = &[
    ("united states", "US"),
    ("usa", "US"),
    ("us", "US"),
    ("world", "WLD"),
    ("global", "WLD"),
    ("china", "CN"),
    ("india", "IN"),
    ("japan", "JP"),
    ("germany", "DE"),
    ("france", "FR"),
    ("united kingdom", "GB"),
    ("uk", "GB"),
    ("britain", "GB"),
    ("brazil", "BR"),
    ("russia", "RU"),
    ("canada", "CA"),
    ("australia", "AU"),
    ("mexico", "MX"),
    ("indonesia", "ID"),
    ("nigeria", "NG"),
];

#[cfg(feature = "websearch")]
fn resolve_country_alias(name: &str) -> String {
    let n = name.trim().to_lowercase();
    if n.is_empty() {
        return "WLD".to_string();
    }
    for (alias, code) in WB_COUNTRIES {
        if n == *alias {
            return code.to_string();
        }
    }
    n.to_uppercase()
}

/// Pure: parse a free-form websearch query into (indicator code, country, year).
#[cfg(feature = "websearch")]
fn parse_websearch_query(query: &str) -> (String, String, Option<u32>) {
    let mut year: Option<u32> = None;
    let mut kept: Vec<&str> = Vec::new();
    for token in query.split_whitespace() {
        if let Ok(y) = token.parse::<u32>() {
            if (1900..=2100).contains(&y) {
                year = Some(y);
                continue;
            }
        }
        kept.push(token);
    }
    let rest = kept.join(" ");
    let rest_lower = rest.to_lowercase();

    let mut indicator: Option<String> = None;
    let mut country_part = rest.clone();
    for (alias, code) in WB_INDICATORS {
        if rest_lower.starts_with(*alias) {
            indicator = Some(code.to_string());
            country_part = rest[alias.len()..].trim().to_string();
            break;
        }
    }
    if indicator.is_none() {
        if let Some((first, remainder)) = rest.split_once(' ') {
            indicator = Some(first.to_string());
            country_part = remainder.trim().to_string();
        } else {
            indicator = Some(rest.clone());
            country_part = String::new();
        }
    }
    let country = resolve_country_alias(&country_part);
    (indicator.unwrap(), country, year)
}

/// Pure: extract the most recent non-null observation from a World Bank JSON body.
#[cfg(feature = "websearch")]
fn parse_world_bank_response(body: &str) -> Result<String, String> {
    let value: serde_json::Value =
        serde_json::from_str(body).map_err(|e| format!("invalid World Bank JSON: {e}"))?;
    let observations = value
        .get(1)
        .and_then(|a| a.as_array())
        .ok_or_else(|| "World Bank response had no observation array".to_string())?;
    let mut chosen: Option<&serde_json::Value> = None;
    for obs in observations {
        if obs.get("value").and_then(|v| v.as_f64()).is_some() {
            chosen = Some(obs);
        }
    }
    let obs = chosen.ok_or_else(|| "no non-null observations returned".to_string())?;
    let indicator = obs
        .get("indicator")
        .and_then(|i| i.get("value"))
        .and_then(|v| v.as_str())
        .unwrap_or("?");
    let country = obs
        .get("country")
        .and_then(|c| c.get("value"))
        .and_then(|v| v.as_str())
        .unwrap_or("?");
    let date = obs.get("date").and_then(|d| d.as_str()).unwrap_or("?");
    let val = obs
        .get("value")
        .and_then(|v| v.as_f64())
        .ok_or_else(|| "missing value".to_string())?;
    Ok(format!("{indicator} — {country} ({date}): {val}"))
}

#[cfg(feature = "websearch")]
fn world_bank_lookup(indicator: &str, country: &str, year: Option<u32>) -> Result<String, String> {
    let date = match year {
        Some(y) => y.to_string(),
        None => "2015:2024".to_string(),
    };
    let url = format!(
        "https://api.worldbank.org/v2/country/{country}/indicator/{indicator}?format=json&date={date}&per_page=20"
    );
    let agent = ureq::AgentBuilder::new().build();
    let response = agent
        .get(&url)
        .call()
        .map_err(|e| format!("World Bank request failed: {e}"))?;
    let body = response
        .into_string()
        .map_err(|e| format!("read World Bank body failed: {e}"))?;
    parse_world_bank_response(&body)
}

#[cfg(feature = "websearch")]
fn cmd_websearch(query: &str) {
    let (indicator, country, year) = parse_websearch_query(query);
    eprintln!("websearch: indicator={indicator} country={country} year={year:?}");
    match world_bank_lookup(&indicator, &country, year) {
        Ok(line) => println!("{line}"),
        Err(e) => {
            eprintln!("websearch error: {e}");
            std::process::exit(1);
        }
    }
}

#[cfg(all(test, feature = "websearch"))]
mod websearch_tests {
    use super::*;

    #[test]
    fn parses_gdp_us_year() {
        let (ind, c, y) = parse_websearch_query("gdp united states 2020");
        assert_eq!(ind, "NY.GDP.MKTP.CD");
        assert_eq!(c, "US");
        assert_eq!(y, Some(2020));
    }

    #[test]
    fn parses_population_world_no_year() {
        let (ind, c, y) = parse_websearch_query("population");
        assert_eq!(ind, "SP.POP.TOTL");
        assert_eq!(c, "WLD");
        assert_eq!(y, None);
    }

    #[test]
    fn parses_raw_indicator_and_country() {
        let (ind, c, _y) = parse_websearch_query("SP.DYN.LE00.IN japan");
        assert_eq!(ind, "SP.DYN.LE00.IN");
        assert_eq!(c, "JP");
    }

    #[test]
    fn parses_response_offline() {
        let body = r#"[{"page":1},[{"indicator":{"id":"NY.GDP.MKTP.CD","value":"GDP (current US$)"},"country":{"id":"US","value":"United States"},"date":"2020","value":21375281000000}]]"#;
        let line = parse_world_bank_response(body).unwrap();
        assert!(line.contains("United States"));
        assert!(line.contains("2020"));
        assert!(line.contains("21375281000000"));
    }
}

#[cfg(test)]
mod t36_tests {
    use super::*;

    #[test]
    fn extracts_operator_expression_with_precedence() {
        // "2 + 3 * 4" must evaluate to 14, not naive (2+3)=5 then (3*4)...
        let expr = extract_arithmetic_expression("what is 2 + 3 * 4?").expect("expr");
        let env = create_env();
        let val = evaluate_expr(&expr, &env).expect("eval");
        assert!((val - 14.0).abs() < 1e-9, "expected 14, got {val}");
    }

    #[test]
    fn extracts_equation_and_splits_lhs() {
        let expr = extract_arithmetic_expression("verify 2 + 3 = 5").expect("expr");
        assert!(expr.contains('='));
        let env = create_env();
        let eq = expr.find('=').unwrap();
        let lhs = &expr[..eq];
        let val = evaluate_expr(lhs, &env).expect("eval lhs");
        assert!((val - 5.0).abs() < 1e-9, "expected 5, got {val}");
    }

    #[test]
    fn modulo_keeps_first_operand() {
        // T42 regression: "%" must not drop the left operand.
        // "10 % 3 = 1" must evaluate to 1.0 and match stated RHS.
        let expr = extract_arithmetic_expression("10 % 3 = 1").expect("expr");
        assert!(expr.contains('%'), "expr dropped modulo: {expr:?}");
        let env = create_env();
        let eq = expr.find('=').unwrap();
        let lhs = &expr[..eq];
        let val = evaluate_expr(lhs, &env).expect("eval lhs");
        assert!((val - 1.0).abs() < 1e-9, "expected 1, got {val}");
        let rhs: f64 = expr[eq + 1..].trim().parse().unwrap();
        assert!((val - rhs).abs() < 1e-9, "lhs {val} != rhs {rhs}");
    }

    #[test]
    fn no_arithmetic_returns_none() {
        assert!(extract_arithmetic_expression("the cat sat on the mat").is_none());
    }

    #[test]
    fn strips_trailing_operator() {
        let expr = extract_arithmetic_expression("compute 2 + 3 =").expect("expr");
        assert!(!expr.ends_with('='), "expr was {expr:?}");
        let env = create_env();
        assert!((evaluate_expr(&expr, &env).unwrap() - 5.0).abs() < 1e-9);
    }
}
